var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이봐, 아저씨.","JPN":"ちょっと、おじさん。","ENG":"Hey, mister.","TWN":"喂，大叔。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"......왜 그러지?","JPN":"……なんだ？","ENG":"What is it?","TWN":"……怎麼了？"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"아무리 그래도 100kg이나 되는 이터니움을 개인이 구할 수 있을 리가 없잖아?","JPN":"いくら何でも、100kgものエタニウムを個人で入手できるわけないじゃない。","ENG":"Do you really think that an individual could get their hands on a hundred kilograms of Eternium?","TWN":"不管再怎麼說，100公斤的永恆之金，都不可能是區區個人能擁有的量吧？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"차라리 지금이라도 실비아나 카일에게 연락해 보는 게 낫지 않을까?","JPN":"今からでも、シルビアやカイルに連絡した方がいいんじゃないの？","ENG":"Don't you think it'd be better to contact Sylvia or Kyle about this?","TWN":"不如我們去聯絡希爾維亞和凱爾，這樣不是比較好？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"나도 그 생각을 안 해 본 건 아니지만......","JPN":"俺もその選択肢を考えてないわけではないが……","ENG":"Actually, that was the first thing that came to my mind,","TWN":"我也不是沒有想過這個辦法。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"아마 무리일 거다.","JPN":"まあ、無理だろうな。","ENG":"but I doubt they could be of help.","TWN":"但恐怕行不通。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"지금 이터니움 국제 시세는 말 그대로 폭발 직전이야.","JPN":"今、エタニウムの国際相場は、いわば暴騰寸前の状態だ。","ENG":"The international price of Eternium is literally through the roof.","TWN":"現在永恆之金的國際行情，就如字面上一樣處於一觸即發的狀況。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"로스트 쉽 파괴 작전, 대규모 침식 증후군 치료용 등으로 이터니움 요구량은 어마어마하게 커진 반면에 이터니움 채굴은 완전히 멈춰 버렸으니까.","JPN":"エタニウムの需要は、ロストシップの破壊作戦や侵食症候群の治療などで大幅に増えた一方で、\\nエタニウムの採掘は完全に止まっちまったからな。","ENG":"The Lost Ship annihilation, mass outbreak of Corruption Syndrome... The demand for Eternium is higher than ever before, whereas the mining of it came to a complete stop.","TWN":"在失落艦船的作戰、治療大規模侵蝕症候群等等的事情上，永恆之金需求量變得極大的同時，永恆之金的開採卻完全停擺了。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"슬쩍 전해 들은 바에 따르면 이미 국가 전략 비축분의 재고도 간당간당한 모양이더군.","JPN":"人づてに聞いたんだが、国家戦略備蓄分の在庫もすでに残りわずかのようだ。","ENG":"One of my sources says that even the national strategic stockpile is empty.","TWN":"就我聽到的傳言，國家戰略儲備的庫存已經到了非常吃緊的狀況。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"이런 상황에서 아무리 엘리트라고 해도 일개 특수부대원이 그런 엄청난 양의 이터니움을 꺼내 쓸 수 있을 리가 없어.","JPN":"こんな状況じゃあ、いくらエリートでも、そんな凄まじい量のエタニウムを調達できるわけない。","ENG":"It's hard to think that special forces agents, however capable they may be, could use so much Eternium at their discretion.","TWN":"在這種情況下，就算他們是菁英，但區區一個特殊部隊的隊員也不可能拿出這麼龐大的永恆之金啊。"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But…","TWN":"但是……"},"stage":{"bg":"ETERNIUM","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그뿐이 아니야.","JPN":"それだけじゃない。","ENG":"That's not all.","TWN":"不只是這個原因。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"함부로 우리 계획을 노출했다간 리플레이서 놈들에게 정보가 샐지도 모른다.","JPN":"下手に俺たちの計画を話すと、リプレイサーどもに情報が漏れるかもしれないぞ。","ENG":"If we share our plan with anyone, it can leak out to the Replacers.","TWN":"如果輕易地公開我們的計畫，情報有可能會洩漏給克隆集團知道也不一定。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"JOHN_MASON_NULL_NULL","text":{"KOREA":"그랬다간 형이 목숨을 걸고 만들어 준 기회가 물거품이 될 거야.","JPN":"そんなことになれば、兄貴が命がけで作ってくれたチャンスが水の泡さ。","ENG":"Ian gave up his life to give us this chance. I won't let it be in vain.","TWN":"那樣的話，我哥賭上性命才創造出的機會，全部就泡湯了。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정보가 새다니...... 그럴 리가 있겠어?","JPN":"情報が漏れるなんて……そんなことある？","ENG":"Leak out? That's not going to happen.","TWN":"情報洩露啊……怎麼可能會有這種事呢？"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누가 리플레이서의 편을 든다고......","JPN":"あのリプレイサーに味方するなんてあるわけ……","ENG":"Who's going to side with the Replacers now?","TWN":"有誰會站在克隆集團那邊啊……"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOHN_MASON_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};